"use strict";

const _ = require("lodash");
const problemsData = require("../../data/problems.json");

/**
 * Normalize tags to lowercase trimmed strings
 * @param {string|string[]} tags
 * @returns {string[]}
 */
function normalizeTags(tags) {
  if (!tags) return [];
  if (typeof tags === "string") {
    // split by comma and trim
    return tags
      .split(",")
      .map(t => t.trim().toLowerCase())
      .filter(t => t.length > 0);
  }
  if (Array.isArray(tags)) {
    return tags
      .map(t => (typeof t === "string" ? t.trim().toLowerCase() : ""))
      .filter(t => t.length > 0);
  }
  return [];
}

/**
 * Filter and return problems with optional filters for difficulty, limit, and tags.
 * Tags filter is case-insensitive and matches problems containing all specified tags.
 * The returned metadata includes normalized tags used for filtering.
 * Sorting is stable by problem id ascending.
 *
 * @param {Object} options
 * @param {string|string[]} [options.tags] - Tags to filter by (case-insensitive)
 * @param {number} [options.difficulty] - Difficulty filter
 * @param {number} [options.limit] - Limit number of results
 * @returns {{problems: Object[], metadata: Object}}
 */
function getProblems({ tags, difficulty, limit } = {}) {
  const normalizedTags = normalizeTags(tags);

  let filtered = problemsData;

  if (typeof difficulty === "number") {
    filtered = filtered.filter(p => p.difficulty === difficulty);
  }

  if (normalizedTags.length > 0) {
    filtered = filtered.filter(p => {
      if (!p.tags || !Array.isArray(p.tags)) return false;
      const problemTags = p.tags.map(t => t.toLowerCase());
      return normalizedTags.every(t => problemTags.includes(t));
    });
  }

  // stable sort by id ascending
  filtered = _.sortBy(filtered, ["id"]);

  if (typeof limit === "number" && limit >= 0) {
    filtered = filtered.slice(0, limit);
  }

  return {
    problems: filtered,
    metadata: {
      tags: normalizedTags,
      difficulty,
      limit,
      total: filtered.length,
    },
  };
}

module.exports = {
  normalizeTags,
  getProblems,
};
